import{c as n,S as h,j as t,m as a}from"./chunks/framework.8aa1YH_s.js";const m=JSON.parse('{"title":"Quản lý điểm thi","description":"","frontmatter":{},"headers":[],"relativePath":"giao-vien/quan-ly-diem-thi.md","filePath":"giao-vien/quan-ly-diem-thi.md","lastUpdated":0}'),l={name:"giao-vien/quan-ly-diem-thi.md"};function c(o,i,e,r,g,s){return h(),t("div",null,[...i[0]||(i[0]=[a('<h1 id="quan-ly-điem-thi" tabindex="-1">Quản lý điểm thi <a class="header-anchor" href="#quan-ly-điem-thi" aria-label="Permalink to “Quản lý điểm thi”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/teacher/score-exam</code></p><p>Nơi bạn xem và quản lý kết quả thi của tất cả học viên trong các khóa do bạn phụ trách.</p><h2 id="bang-điem" tabindex="-1">Bảng điểm <a class="header-anchor" href="#bang-điem" aria-label="Permalink to “Bảng điểm”">​</a></h2><p>Cột chính:</p><ul><li><strong>Học viên</strong> (tên, SĐT)</li><li><strong>Khóa học / Lớp</strong></li><li><strong>Tên đề thi</strong></li><li><strong>Loại</strong> (Đề ôn khóa / Đề chuyên đề / Đề mẫu HSA-TSA-THPT / Kiểm tra đầu vào)</li><li><strong>Ngày làm</strong></li><li><strong>Thời gian làm bài thực tế</strong></li><li><strong>Tổng điểm</strong> / Tổng điểm tối đa</li><li><strong>Số lần làm</strong></li><li><strong>Trạng thái</strong> (Đã chấm tự động / Đang chờ chấm tay / Đã xác nhận)</li></ul><h2 id="bo-loc" tabindex="-1">Bộ lọc <a class="header-anchor" href="#bo-loc" aria-label="Permalink to “Bộ lọc”">​</a></h2><ul><li>Theo <strong>Khóa học</strong> / <strong>Lớp</strong></li><li>Theo <strong>Đề thi</strong></li><li>Theo <strong>Khoảng thời gian</strong></li><li>Theo <strong>Học viên</strong> (tên/SĐT)</li><li>Theo <strong>Mức điểm</strong> (vd: dưới trung bình / từ X-Y điểm)</li><li>Theo <strong>Loại đề</strong></li></ul><h2 id="xem-chi-tiet-bai-lam" tabindex="-1">Xem chi tiết bài làm <a class="header-anchor" href="#xem-chi-tiet-bai-lam" aria-label="Permalink to “Xem chi tiết bài làm”">​</a></h2><p>Bấm vào dòng → mở trang chi tiết:</p><ul><li>Từng câu hỏi: đáp án học viên, đáp án đúng, đúng/sai.</li><li>Tổng điểm theo phần / chuyên đề.</li><li>Thời gian làm từng câu (nếu hệ thống ghi nhận).</li></ul><p>Hữu ích khi:</p><ul><li>Học viên khiếu nại &quot;câu này em làm đúng mà sao bị sai&quot;.</li><li>Phân tích lỗi để chỉ ra trong buổi học sau.</li></ul><h2 id="cham-tay-đoi-voi-cau-tu-luan" tabindex="-1">Chấm tay (đối với câu tự luận) <a class="header-anchor" href="#cham-tay-đoi-voi-cau-tu-luan" aria-label="Permalink to “Chấm tay (đối với câu tự luận)”">​</a></h2><p>Đối với câu hỏi không thể chấm tự động (tự luận, vẽ hình):</p><ol><li>Mở chi tiết bài.</li><li>Đến câu cần chấm.</li><li>Đọc bài làm (text / ảnh / file).</li><li>Nhập điểm + nhận xét.</li><li>Lưu.</li><li>Tổng điểm sẽ được cộng lại tự động.</li></ol><h2 id="phan-tich-điem" tabindex="-1">Phân tích điểm <a class="header-anchor" href="#phan-tich-điem" aria-label="Permalink to “Phân tích điểm”">​</a></h2><p>Tab <strong>Phân tích</strong> / <strong>Báo cáo</strong>:</p><h3 id="phan-phoi-điem" tabindex="-1">Phân phối điểm <a class="header-anchor" href="#phan-phoi-điem" aria-label="Permalink to “Phân phối điểm”">​</a></h3><ul><li>Biểu đồ histogram số học viên theo khoảng điểm.</li><li>Xác định: lớp đang ở mức nào? Có quá nhiều người &lt; trung bình?</li></ul><h3 id="cau-sai-nhieu-nhat" tabindex="-1">Câu sai nhiều nhất <a class="header-anchor" href="#cau-sai-nhieu-nhat" aria-label="Permalink to “Câu sai nhiều nhất”">​</a></h3><ul><li>Top 10 câu hỏi mà nhiều học viên làm sai.</li><li>Sử dụng để biết <strong>chủ đề nào cần dạy lại</strong>.</li></ul><h3 id="so-sanh-giua-cac-lop" tabindex="-1">So sánh giữa các lớp <a class="header-anchor" href="#so-sanh-giua-cac-lop" aria-label="Permalink to “So sánh giữa các lớp”">​</a></h3><ul><li>Nếu cùng 1 đề thi được làm bởi nhiều lớp, so điểm trung bình từng lớp.</li></ul><h3 id="xu-huong-hoc-vien" tabindex="-1">Xu hướng học viên <a class="header-anchor" href="#xu-huong-hoc-vien" aria-label="Permalink to “Xu hướng học viên”">​</a></h3><ul><li>Tiến bộ theo thời gian: học viên có cải thiện không?</li><li>Học viên cần được hỗ trợ.</li></ul><h2 id="xuat-excel-pdf" tabindex="-1">Xuất Excel / PDF <a class="header-anchor" href="#xuat-excel-pdf" aria-label="Permalink to “Xuất Excel / PDF”">​</a></h2><ul><li>Bấm <strong>Xuất Excel</strong> để tải bảng điểm theo bộ lọc.</li><li>Bấm <strong>Xuất PDF</strong> cho từng học viên (báo cáo cá nhân, có thể gửi phụ huynh).</li></ul><h2 id="cac-xu-ly-đac-biet" tabindex="-1">Các xử lý đặc biệt <a class="header-anchor" href="#cac-xu-ly-đac-biet" aria-label="Permalink to “Các xử lý đặc biệt”">​</a></h2><h3 id="huy-bai-thi" tabindex="-1">Hủy bài thi <a class="header-anchor" href="#huy-bai-thi" aria-label="Permalink to “Hủy bài thi”">​</a></h3><ul><li>Khi học viên báo &quot;mạng lag mất bài&quot; hoặc gian lận:</li><li>Mở chi tiết → bấm <strong>Hủy bài</strong> → ghi lý do.</li><li>Học viên có thể làm lại nếu đề cho phép.</li></ul><h3 id="cho-phep-lam-lai" tabindex="-1">Cho phép làm lại <a class="header-anchor" href="#cho-phep-lam-lai" aria-label="Permalink to “Cho phép làm lại”">​</a></h3><ul><li>Một số đề mặc định chỉ 1 lần. Nếu muốn cho học viên làm lại:</li><li>Mở chi tiết bài → <strong>Cấp lượt làm thêm</strong>.</li></ul><h3 id="cong-điem-thu-cong" tabindex="-1">Cộng điểm thủ công <a class="header-anchor" href="#cong-điem-thu-cong" aria-label="Permalink to “Cộng điểm thủ công”">​</a></h3><ul><li>Khi có câu lỗi đề và bạn quyết định cộng điểm cho tất cả:</li><li>Vào <strong>Hành động hàng loạt → Cộng điểm</strong>.</li><li>Nhập số điểm + lý do.</li></ul><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Bài thi của học viên ở trạng thái &quot;Đang chấm&quot; mãi không xong?</strong> → Có thể có câu tự luận chờ chấm tay. Mở chi tiết → tìm câu chưa có điểm.</p><p><strong>Học viên báo điểm không đúng?</strong> → Mở chi tiết, đối chiếu từng câu. Nếu có sai sót, sửa thủ công.</p><p><strong>Tôi cần báo cáo điểm cho phụ huynh.</strong> → Lọc theo học viên → <strong>Xuất PDF báo cáo cá nhân</strong>.</p><p><strong>Muốn so sánh kết quả của 2 đợt thi thử HSA?</strong> → Lọc theo tên đề + khoảng thời gian, xuất Excel rồi pivot. Hoặc dùng tab <strong>Phân tích → So sánh</strong> nếu hệ thống có.</p>',40)])])}const d=n(l,[["render",c]]);export{m as __pageData,d as default};
